package ru.memearena.meme.domain;
import jakarta.persistence.*; import java.time.Instant; import java.util.UUID;
@Entity @Table(name="meme") public class Meme { @Id private UUID id; private String title; @Column(name="image_url") private String imageUrl; @Column(name="media_asset_id") private UUID mediaAssetId; @Column(name="source_url") private String sourceUrl; @Column(name="uploader_id") private UUID uploaderId; @Enumerated(EnumType.STRING) @Column(name="moderation_status") private ModerationStatus moderationStatus; @Column(name="moderated_at") private Instant moderatedAt; @Column(name="moderation_reason") private String moderationReason; private int rating; private long wins; private long losses; @Column(name="battles_count") private long battlesCount; @Column(name="created_at") private Instant createdAt; @Column(name="updated_at") private Instant updatedAt; protected Meme(){} public Meme(UUID id,String title,String imageUrl,UUID mediaAssetId,String sourceUrl,UUID uploaderId,Instant now){this.id=id;this.title=title;this.imageUrl=imageUrl;this.mediaAssetId=mediaAssetId;this.sourceUrl=sourceUrl;this.uploaderId=uploaderId;this.moderationStatus=ModerationStatus.PENDING;this.rating=1500;this.createdAt=now;this.updatedAt=now;} public UUID getId(){return id;} public String getTitle(){return title;} public String getImageUrl(){return imageUrl;} public UUID getMediaAssetId(){return mediaAssetId;} public String getSourceUrl(){return sourceUrl;} public UUID getUploaderId(){return uploaderId;} public ModerationStatus getModerationStatus(){return moderationStatus;} public Instant getModeratedAt(){return moderatedAt;} public String getModerationReason(){return moderationReason;} public int getRating(){return rating;} public long getWins(){return wins;} public long getLosses(){return losses;} public long getBattlesCount(){return battlesCount;} public Instant getCreatedAt(){return createdAt;} public void approve(Instant now){moderationStatus=ModerationStatus.APPROVED;moderatedAt=now;moderationReason=null;updatedAt=now;} public void reject(Instant now,String reason){moderationStatus=ModerationStatus.REJECTED;moderatedAt=now;moderationReason=reason;updatedAt=now;} public void win(int newRating,Instant now){wins++;battlesCount++;rating=newRating;updatedAt=now;} public void lose(int newRating,Instant now){losses++;battlesCount++;rating=newRating;updatedAt=now;} }
